class Solution {
    public String crackSafe(int n, int k) {
        StringBuilder ans = new StringBuilder();
        for (int i = 0; i < n - 1; i++) {
            ans.append("0");
        }
        HashSet<String> seen = new HashSet<>();
        dfs(ans, seen, n, k);
        return ans.toString();
    }

    private void dfs(StringBuilder ans, HashSet<String> seen, int n, int k) {
        for (int i = 0; i < k; i++) {
            String curr = ans.substring(ans.length() - n + 1) + i;
            if (!seen.contains(curr)) {
                seen.add(curr);
                ans.append(i);
                dfs(ans, seen, n, k);
                if (ans.length() >= (int) Math.pow(k, n)) {
                    return;
                }
                ans.deleteCharAt(ans.length() - 1);
                seen.remove(curr);
            }
        }
    }
}
